/* adm-item-substitution-sql-oracle.xml - selectPkCountSubstitution */ 
SELECT COUNT(1)
FROM 
	( SELECT A.ICKEY
	   FROM TADMIN_MST_ICSB A
	   INNER JOIN TADMIN_MST_IC B
	   		   ON A.OWKEY = B.OWKEY
			  AND A.ICKEY = B.ICKEY
	 WHERE  1 = 1

	   AND #{SEARCH_CONDITION}


	   AND A.OWKEY = #{owkey}


	   AND A.ICKEY = #{ickey}


	   AND A.SBKEY = #{sbkey}


	   UNION ALL
	SELECT  A.ICKEY
	  FROM 	TADMIN_MST_IC A 
     WHERE 	A.OWKEY =  #{owkey}
	   AND 	A.ICKEY = #{sbkey}


)

/* adm-item-substitution-sql-oracle.xml - selectSubstitutionCount */ SELECT COUNT(1) FROM ( SELECT A.ICKEY FROM TADMIN_MST_ICSB A INNER JOIN TADMIN_MST_IC B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
)

/* adm-item-substitution-sql-oracle.xml - selectListSubstitution */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.* FROM ( SELECT '0' AS CHK ,A.OWKEY ,(SELECT OWNM FROM TADMIN_MST_OW OW WHERE OW.OWKEY = A.OWKEY) AS OWNM ,A.ICKEY ,B.ICNM ,A.SBKEY ,B.SPEC ,A.ICUNITTYPE ,A.UDF1 ,A.UDF2 ,A.UDF3 ,A.CLOSDATE ,A.INSERTDATE ,A.UPDATEDATE ,A.INSERTURKEY ,A.UPDATEURKEY ,B.ICUNITKEY ,A.DELYN ,B.UDF3 AS CHGUOM FROM TADMIN_MST_ICSB A LEFT OUTER JOIN TADMIN_MST_IC B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY
AND #{SEARCH_CONDITION}
) A
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.insert:
		/* adm-item-substitution-sql-oracle.xml - insertTAdminMstIcsb */
		INSERT INTO TADMIN_MST_ICSB	(
    		OWKEY
			,ICKEY
			,SBKEY
			,ICUNITTYPE
			,UDF1
			,UDF2
			,UDF3
			,CLOSDATE
			,INSERTDATE
			,INSERTURKEY
			,UPDATEDATE
			,UPDATEURKEY
		) VALUES (
			#{owkey}
			,#{ickey}
			,#{sbkey}
			,COALESCE(#{icunittype}, 'EA')
			,#{udf1}
			,#{udf2}
			,#{udf3}
			,SUBSTR(#{closdate}, 0, 14)
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

mapper.update:
		/* adm-item-substitution-sql-oracle.xml - updateTAdminMstIcsb */
		UPDATE 	TADMIN_MST_ICSB 
		   SET	ICUNITTYPE = #{icunittype}
           		,UDF1 = #{udf1}
           		,UDF2 = #{udf2}
           		,UDF3 = #{udf3}
           		,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
		        ,UPDATEDATE = #{sysdate}
		        ,UPDATEURKEY = #{surkey}
		 WHERE	OWKEY = #{owkey}
		   AND	ICKEY = #{ickey}
		   AND	SBKEY = #{sbkey}

