FROM	TADMIN_MST_ICSB A
WHERE A.OWKEY = #{owkey}
  AND A.ICKEY = #{ickey}
  AND A.SBKEY = #{sbkey}
  AND A.DELYN = 'Y'

/* adm-item-substitution-sql-oracle.xml - selectTAdminMstIcsbxct */
SELECT	'0' AS CHK
    	,A.OWKEY
		,A.ICKEY
		,A.SBKEY
		,A.CTKEY
      	,B.CTNM
  FROM	TADMIN_MST_ICSBXCT A 
  INNER JOIN TADMIN_MST_CT B
