mapper.select:
/* adm-item-substitution-sql-oracle.xml - selectPkCountIcxCt */
SELECT 	COUNT(*)
FROM 	TADMIN_MST_ICXCT
WHERE 	CTKEY = #{ctkey}
AND 	ICKEY = #{ickey}

/* adm-item-substitution-sql-oracle.xml - selectPkCountIcuttypexIcxCt */
SELECT 	COUNT(*)
FROM 	(SELECT A.ICKEY 
				,A.ICUNITKEY
				,A.OWKEY 
				,B.CTKEY
		FROM 	TADMIN_MST_IC A
		INNER JOIN TADMIN_MST_ICXCT B
				ON A.OWKEY = B.OWKEY
			   AND A.ICKEY = B.ICKEY
		) TB1
INNER JOIN TADMIN_MST_ICUTXTYPEXCT TB2
		ON TB1.CTKEY = TB2.CTKEY
	   AND TB1.ICUNITKEY = TB2.ICUNITKEY
WHERE 	TB1.CTKEY = #{ctkey}
AND 	TB1.OWKEY = #{owkey}
AND 	TB1.ICKEY = #{ickey}
AND 	TB2.ICUNITTYPE = #{icunittype}
